def win_connect_mdb(mdb_path):
    if sys.platform not in ('win32','cli'):
        raise Exception('This function is available for use in Windows only.')
    mdb_driver = [d for d in pyodbc.drivers() if 'Microsoft Access Driver (*.mdb' in d]
